'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Globe, Plus, Trash2, Fingerprint, LogOut,
  Loader2, CheckCircle, Package, AlertCircle, Save,
  Sun, Moon, Users, User, Shield
} from 'lucide-react';
import { startRegistration } from '@simplewebauthn/browser';
import { useConfirm } from '@/components/ConfirmContext';

export default function AdminDashboard() {
  const [session, setSession] = useState<{ username: string } | null>(null);
  const [globalExams, setGlobalExams] = useState<any[]>([]);
  const [users, setUsers] = useState<any[]>([]);
  const [adminsList, setAdminsList] = useState<any[]>([]);
  const [jsonInput, setJsonInput] = useState('');
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);

  const [dark, setDark] = useState(false);
  useEffect(() => {
    if (localStorage.getItem("apaes_dark") === "1") setDark(true);
  }, []);
  const toggleDark = () => setDark(d => { localStorage.setItem("apaes_dark", d ? "0" : "1"); return !d; });

  const router = useRouter();

  useEffect(() => {
    fetchSession();
    fetchGlobalExams();
    fetchUsersAndAdmins();
  }, []);

  const fetchSession = async () => {
    try {
      const res = await fetch('/api/admin/global-exams');
      if (res.status === 401) {
        router.push('/admin/login');
        return;
      }
      setSession({ username: 'Admin' });
    } catch {
      router.push('/admin/login');
    }
  };

  const fetchGlobalExams = async () => {
    try {
      const res = await fetch('/api/admin/global-exams');
      if (res.ok) {
        const data = await res.json();
        setGlobalExams(data);
      }
    } finally {
      setLoading(false);
    }
  };

  const fetchUsersAndAdmins = async () => {
    try {
      const res = await fetch('/api/admin/users');
      if (res.ok) {
        const data = await res.json();
        setUsers(data.users || []);
        setAdminsList(data.admins || []);
      }
    } catch { }
  };

  const showMsg = (text: string, type: 'success' | 'error') => {
    setMessage({ text, type });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleAddPasskey = async () => {
    setActionLoading(true);
    try {
      const resOptions = await fetch('/api/admin/passkey/options', { method: 'POST' });
      const options = await resOptions.json();
      if (options.error) throw new Error(options.error);

      const attResp = await startRegistration({ optionsJSON: options });
      const resVerify = await fetch('/api/admin/passkey/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(attResp),
      });

      const data = await resVerify.json();
      if (data.error) throw new Error(data.error);

      showMsg('Passkey añadida (password desactivado)', 'success');
      fetchUsersAndAdmins(); // Refresh admin status
    } catch (err: any) {
      showMsg(err.message, 'error');
    } finally {
      setActionLoading(false);
    }
  };

  const handleUploadExam = async () => {
    if (!jsonInput.trim()) return;
    setActionLoading(true);
    try {
      const parsed = JSON.parse(jsonInput);
      if (!parsed.preguntas) throw new Error('JSON inválido: falta campo "preguntas"');

      const formatted = parsed.preguntas.map((p: any) => ({
        id: p.id,
        text: p.enunciado || "Sin enunciado",
        options: Object.values(p.opciones || {}),
        correctAnswer: p.respuesta_correcta,
        explanation: p.explicacion,
      }));

      const res = await fetch('/api/admin/global-exams', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          metadata: parsed.metadata || { asignatura: 'Ensayo Global' },
          data: formatted
        }),
      });

      if (!res.ok) throw new Error('Error al subir el ensayo');

      showMsg('Ensayo global publicado', 'success');
      setJsonInput('');
      fetchGlobalExams();
    } catch (err: any) {
      showMsg(err.message, 'error');
    } finally {
      setActionLoading(false);
    }
  };

  const { confirm } = useConfirm();

  const handleDeleteGlobal = async (id: number) => {
    const ok = await confirm({
      title: "Eliminar Ensayo Global",
      message: "¿Eliminar este ensayo global para todos los usuarios? Esta acción no se puede deshacer.",
      confirmLabel: "Eliminar",
      type: "danger"
    });
    if (!ok) return;
    try {
      await fetch('/api/admin/global-exams', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id }),
      });
      fetchGlobalExams();
      showMsg('Ensayo eliminado', 'success');
    } catch (err: any) {
      showMsg(err.message, 'error');
    }
  };

  const handleDeleteEntry = async (id: string, type: 'user' | 'admin') => {
    const ok = await confirm({
      title: `Eliminar ${type === 'admin' ? 'Administrador' : 'Usuario'}`,
      message: `¿Eliminar este ${type === 'admin' ? 'administrador' : 'usuario'} del sistema?`,
      confirmLabel: "Eliminar",
      type: "danger"
    });
    if (!ok) return;
    try {
      const res = await fetch('/api/admin/users', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id, type }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);

      showMsg(`${type === 'admin' ? 'Admin' : 'Usuario'} eliminado`, 'success');
      fetchUsersAndAdmins();
    } catch (err: any) {
      showMsg(err.message, 'error');
    }
  };

  const handleLogout = async () => {
    await fetch('/api/auth/session', { method: 'DELETE' });
    document.cookie = 'auth_admin_id=; path=/; expires=Thu, 01 Jan 1970 00:00:01 GMT;';
    router.push('/admin/login');
  };

  const bg = dark ? "bg-[#0d0d18]" : "bg-[#ded9ed]";
  const navBg = dark ? "bg-[#1a0f38]" : "bg-[#351b69]";
  const tx = dark ? "text-slate-100" : "text-black";
  const border = dark ? "border-white/10" : "border-black";

  if (loading) {
    return <div className={`min-h-screen flex items-center justify-center ${bg} ${tx}`}><Loader2 className="animate-spin" /></div>;
  }

  return (
    <div className={`min-h-screen transition-all duration-300 ${bg} ${tx} font-sans p-6 md:p-12`}>
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <header className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 mb-12">
          <div>
            <h1 className="text-5xl font-black tracking-tighter uppercase flex items-center gap-4 drop-shadow-sm">
              Panel de Control
            </h1>
            <p className={`font-bold uppercase text-xs tracking-widest mt-2 ${dark ? "text-slate-400" : "text-slate-600"}`}>
              Gestión Maestra de aPAES
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <button
              onClick={toggleDark}
              className={`p-3 rounded-xl border-2 transition-all ${dark ? "bg-white/10 border-white/20 text-white" : "bg-white border-black"}`}
            >
              {dark ? <Sun size={24} /> : <Moon size={24} />}
            </button>
            <button
              onClick={handleAddPasskey}
              disabled={actionLoading}
              className={`flex items-center gap-2 px-6 py-3 rounded-xl font-extrabold text-sm shadow-[4px_4px_0_#000] active:translate-x-0.5 active:translate-y-0.5 active:shadow-none transition-all ${dark ? "bg-slate-800 border-white/20 text-indigo-300" : "bg-[#6c40d6] border-black text-white"}`}
            >
              <Fingerprint size={20} /> Añadir Passkey
            </button>
            <button
              onClick={handleLogout}
              className={`flex items-center gap-2 px-6 py-3 rounded-xl font-extrabold text-sm shadow-[4px_4px_0_#000] active:translate-x-0.5 active:translate-y-0.5 active:shadow-none transition-all ${dark ? "bg-rose-900/40 border-white/10 text-rose-200" : "bg-rose-500 border-black text-white"}`}
            >
              <LogOut size={20} /> Salir
            </button>
          </div>
        </header>

        {
          message && (
            <div className={`mb-8 p-5 rounded-2xl border-[3px] flex items-center gap-4 font-black uppercase text-sm animate-in fade-in slide-in-from-top-4 ${message.type === 'success' ? 'bg-emerald-500/10 border-emerald-500 text-emerald-500' : 'bg-rose-500/10 border-rose-500 text-rose-500'}`}>
              {message.type === 'success' ? <CheckCircle size={24} /> : <AlertCircle size={24} />}
              {message.text}
            </div>
          )
        }

        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">

          {/* Main Controls Section */}
          <div className="xl:col-span-8 space-y-8">

            {/* Global Exams Card */}
            <div className={`border-[4px] rounded-3xl p-8 transition-colors ${dark ? "bg-[#12112a] border-white/10 shadow-[8px_8px_0_rgba(255,255,255,0.05)]" : "bg-white border-black shadow-[8px_8px_0_#000]"}`}>
              <h2 className="text-2xl font-black uppercase mb-8 flex items-center gap-3">
                <Globe size={32} className="text-[#6c40d6]" />
                Ensayos Globales
              </h2>

              {globalExams.length === 0 ? (
                <div className={`py-16 text-center font-bold border-[3px] border-dashed rounded-2xl ${dark ? "border-white/10 text-slate-500" : "border-slate-300 text-slate-400"}`}>
                  No hay ensayos publicados. Sube uno a la derecha.
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {globalExams.map(exam => (
                    <div key={exam.id} className={`border-[3px] rounded-2xl p-5 flex justify-between items-center group transition-transform hover:-translate-y-1 ${dark ? "bg-white/5 border-white/10" : "bg-[#f4f2f9] border-black"}`}>
                      <div>
                        <div className="flex items-center gap-2 mb-2">
                          <span className="bg-[#6c40d6] text-white text-[10px] font-black px-2 py-0.5 rounded border border-black shadow-[2px_2px_0_#000]">GLOBAL</span>
                          <h3 className="font-black text-lg tracking-tight">{exam.metadata?.asignatura}</h3>
                        </div>
                        <p className={`text-xs font-extrabold uppercase ${dark ? "text-slate-400" : "text-slate-500"}`}>
                          {exam.data.length} preguntas • {exam.metadata?.año || '2024'}
                        </p>
                      </div>
                      <button
                        onClick={() => handleDeleteGlobal(exam.id)}
                        className={`transition-colors p-3 rounded-xl border-2 ${dark ? "text-slate-500 hover:text-rose-400 border-transparent hover:bg-rose-500/10" : "text-slate-400 hover:text-rose-600 border-transparent hover:bg-rose-100"}`}
                      >
                        <Trash2 size={24} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* User Management Card */}
            <div className={`border-[4px] rounded-3xl p-8 transition-colors ${dark ? "bg-[#12112a] border-white/10 shadow-[8px_8px_0_rgba(255,255,255,0.05)]" : "bg-white border-black shadow-[8px_8px_0_#000]"}`}>
              <h2 className="text-2xl font-black uppercase mb-8 flex items-center gap-3">
                <Users size={32} className="text-emerald-500" />
                Control de Personal
              </h2>

              <div className="space-y-8">
                {/* Admins Sub-section */}
                <div>
                  <h3 className={`text-xs font-black uppercase tracking-[0.2em] mb-4 flex items-center gap-2 ${dark ? "text-indigo-400" : "text-[#6c40d6]"}`}>
                    <Shield size={16} /> Administradores
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {adminsList.map(adm => (
                      <div key={adm.id} className={`border-2 rounded-2xl p-4 flex justify-between items-center ${dark ? "bg-indigo-500/5 border-indigo-500/20" : "bg-[#f0edf9] border-black/10"}`}>
                        <div className="flex items-center gap-3">
                          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black ${dark ? "bg-indigo-500/20 text-indigo-300" : "bg-[#6c40d6] text-white"}`}>
                            {adm.username[0].toUpperCase()}
                          </div>
                          <div>
                            <p className="font-extrabold">{adm.username}</p>
                            <p className="text-[10px] font-black uppercase opacity-60">
                              {adm.hasPassword ? 'Con Contraseña' : 'Solo Passkey'}
                            </p>
                          </div>
                        </div>
                        <button
                          onClick={() => handleDeleteEntry(adm.id, 'admin')}
                          className="text-rose-400 hover:scale-110 transition-transform p-2"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Users Sub-section */}
                <div>
                  <h3 className={`text-xs font-black uppercase tracking-[0.2em] mb-4 flex items-center gap-2 ${dark ? "text-emerald-500" : "text-emerald-600"}`}>
                    <User size={16} /> Usuarios (Estudiantes)
                  </h3>
                  {users.length === 0 ? (
                    <p className="text-xs font-bold opacity-40 italic">No hay usuarios registrados.</p>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                      {users.map(u => (
                        <div key={u.id} className={`border-2 rounded-xl p-3 flex justify-between items-center ${dark ? "bg-white/5 border-white/5" : "bg-white border-black/5"}`}>
                          <span className="font-bold text-sm truncate max-w-[120px]">{u.username}</span>
                          <button
                            onClick={() => handleDeleteEntry(u.id, 'user')}
                            className="text-slate-400 hover:text-rose-400 transition-colors p-1"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* Sidebar Section */}
          <div className="xl:col-span-4 space-y-6">
            <div className={`border-[4px] rounded-3xl p-8 sticky top-12 transition-colors ${dark ? "bg-[#12112a] border-white/10 shadow-[8px_8px_0_rgba(255,255,255,0.05)]" : "bg-white border-black shadow-[8px_8px_0_#000]"}`}>
              <h2 className="text-2xl font-black uppercase mb-6 flex items-center gap-3">
                <Plus size={32} className="text-emerald-500" />
                Publicar
              </h2>
              <p className={`text-xs font-black uppercase tracking-[0.15em] mb-4 ${dark ? "text-slate-400" : "text-slate-500"}`}>JSON del ensayo</p>

              <textarea
                className={`w-full h-96 rounded-2xl p-5 font-mono text-[10px] focus:outline-none border-2 transition-all ${dark ? "bg-[#0d0d18] border-white/10 text-indigo-100 focus:border-[#6c40d6]" : "bg-[#f4f2f9] border-black text-black focus:border-[#6c40d6]"}`}
                placeholder={'{\n  "metadata": { "asignatura": "..." },\n  "preguntas": [...]\n}'}
                value={jsonInput}
                onChange={e => setJsonInput(e.target.value)}
              />

              <button
                onClick={handleUploadExam}
                disabled={actionLoading}
                className={`w-full mt-6 py-5 rounded-2xl border-[4px] border-black font-black text-xl flex items-center justify-center gap-3 shadow-[6px_6px_0_#000] active:translate-x-1 active:translate-y-1 active:shadow-none transition-all ${dark ? "bg-emerald-700 text-white" : "bg-emerald-500 text-white"}`}
              >
                {actionLoading ? <Loader2 className="animate-spin" /> : <><Save size={24} /> Publicar</>}
              </button>

              <div className={`mt-8 p-5 rounded-2xl border-2 ${dark ? "bg-indigo-500/5 border-indigo-500/10" : "bg-[#f0edf9] border-black/5"}`}>
                <h3 className="font-black text-xs uppercase mb-3 text-indigo-400 flex items-center gap-2">
                  <AlertCircle size={16} /> Instrucción
                </h3>
                <ul className="text-[11px] font-bold space-y-2 opacity-70 list-disc list-inside">
                  <li>Formato JSON estructurado</li>
                  <li>Metadatos requeridos (asignatura, año)</li>
                  <li>Las imágenes deben ser URLs válidas</li>
                </ul>
              </div>
            </div>
          </div>
        </div>
      </div >
    </div >
  );
}

